<template><div class="card p-3"><div class="flex items-center justify-between text-xs"><template v-for="(s,i) in steps" :key="s"><div class="flex-1 flex items-center"><div class="w-6 h-6 rounded-full border flex items-center justify-center" :class="i+1<=current?'border-red-400 text-red-500':'border-slate-300 text-slate-400'">{{ i+1 }}</div><div class="ml-2">{{ s }}</div><div v-if="i<steps.length-1" class="h-0.5 flex-1 mx-2" :class="i+1<current?'bg-red-400':'bg-slate-200'"></div></div></template></div></div></template>
